module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    reg [15:0] quotient;

    always @(*) begin
        dividend = A[15:8];
        divisor = B;
        remainder = 0;

        if (dividend >= divisor) begin
            quotient = 1;
            remainder = dividend - divisor;
        end else begin
            quotient = 0;
            remainder = dividend;
        end

        result = {remainder, A[7:0]};
        odd = quotient;
    end

endmodule
